import{_ as e,o as a,c as o,a0 as d}from"./chunks/framework.BJ65gTIr.js";const u=JSON.parse('{"title":"Roadmap","description":"claude-code-Go development roadmap","frontmatter":{"title":"Roadmap","description":"claude-code-Go development roadmap"},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md","lastUpdated":1775550241000}'),r={name:"roadmap.md"};function n(i,t,s,l,h,c){return a(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>Here&#39;s the development roadmap for claude-code-Go, organized into three phases.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>Status</th><th>Description</th></tr></thead><tbody><tr><td>Phase 1</td><td>✅ Complete</td><td>Core foundation - Agent loop, tools, permission, MCP, SSE, sessions</td></tr><tr><td>Phase 2</td><td>✅ Complete</td><td>Enhanced capabilities - Skills, multi-provider, session resume</td></tr><tr><td>Phase 3</td><td>🔮 Planned</td><td>Advanced features - IDE integration, collaboration, cloud</td></tr></tbody></table><hr><h2 id="phase-1-foundation-✅-complete" tabindex="-1">Phase 1: Foundation ✅ Complete <a class="header-anchor" href="#phase-1-foundation-✅-complete" aria-label="Permalink to &quot;Phase 1: Foundation ✅ Complete&quot;">​</a></h2><p>The first phase established the core infrastructure for the AI coding assistant.</p><h3 id="completed-features" tabindex="-1">Completed Features <a class="header-anchor" href="#completed-features" aria-label="Permalink to &quot;Completed Features&quot;">​</a></h3><ul><li><strong>Agent Loop</strong> — Autonomous &quot;think → act → observe&quot; cycle with stop_reason dispatch</li><li><strong>9 Built-in Tools</strong> — 6 core (Read, Write, Edit, Glob, Grep, Bash) + 3 enhanced (Diff view, Tree, WebFetch)</li><li><strong>Permission System</strong> — Three-tier model with rule-based matching and session memory</li><li><strong>MCP Integration</strong> — Model Context Protocol with stdio transport and JSON-RPC</li><li><strong>SSE Streaming</strong> — Real-time token-by-token response with custom parser</li><li><strong>Session Persistence</strong> — Save and restore conversation state</li><li><strong>Hooks System</strong> — Pre/post execution callbacks for extensibility</li></ul><hr><h2 id="phase-2-enhanced-capabilities-✅-complete" tabindex="-1">Phase 2: Enhanced Capabilities ✅ Complete <a class="header-anchor" href="#phase-2-enhanced-capabilities-✅-complete" aria-label="Permalink to &quot;Phase 2: Enhanced Capabilities ✅ Complete&quot;">​</a></h2><p>Phase 2 adds more powerful features to improve usability and flexibility.</p><h3 id="completed-features-1" tabindex="-1">Completed Features <a class="header-anchor" href="#completed-features-1" aria-label="Permalink to &quot;Completed Features&quot;">​</a></h3><ul><li><strong>Skills System</strong> — Custom commands and reusable workflows (e.g., <code>/review-pr</code>, <code>/deploy</code>)</li><li><strong>Multi-Provider Support</strong> — Anthropic, OpenAI, and any OpenAI-compatible API</li><li><strong>Session Resume</strong> — Load previous conversations and continue seamlessly</li><li><strong>Enhanced Tools</strong> — Diff view, tree visualization, web fetching</li><li><strong>Manual Compaction</strong> — <code>/compact</code> command to reduce context size</li><li><strong>Auto-Update</strong> — <code>/update</code> command for version checking and updates</li></ul><hr><h2 id="phase-3-advanced-features-🔮-planned" tabindex="-1">Phase 3: Advanced Features 🔮 Planned <a class="header-anchor" href="#phase-3-advanced-features-🔮-planned" aria-label="Permalink to &quot;Phase 3: Advanced Features 🔮 Planned&quot;">​</a></h2><p>Future plans to bring more advanced capabilities and better integration.</p><h3 id="planned-features" tabindex="-1">Planned Features <a class="header-anchor" href="#planned-features" aria-label="Permalink to &quot;Planned Features&quot;">​</a></h3><ul><li><strong>VS Code Extension</strong> — Native IDE integration with rich UI</li><li><strong>Desktop Application</strong> — Standalone GUI with full feature set</li><li><strong>Team Collaboration</strong> — Shared workflows, team dashboards, permissions</li><li><strong>Cloud Agent</strong> — Remote execution, API endpoints, monitoring</li><li><strong>Plugin Marketplace</strong> — Community-created skills and extensions</li></ul><h3 id="vision" tabindex="-1">Vision <a class="header-anchor" href="#vision" aria-label="Permalink to &quot;Vision&quot;">​</a></h3><p>Phase 3 aims to make claude-code-Go a full-fledged development environment, bridging the gap between CLI and IDE while maintaining the simplicity and performance of Go.</p><hr><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>Want to influence the roadmap? See our <a href="/claude-code-Go/feedback.html">Feedback</a> page for how to report issues and submit feature requests.</p><hr><h2 id="feature-comparison" tabindex="-1">Feature Comparison <a class="header-anchor" href="#feature-comparison" aria-label="Permalink to &quot;Feature Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Phase 1</th><th>Phase 2</th><th>Claude Code</th></tr></thead><tbody><tr><td>Agent Loop</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Built-in Tools</td><td>6 core</td><td>9 total</td><td>20+</td></tr><tr><td>Permission System</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>MCP Integration</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>SSE Streaming</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Session Persistence</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Session Resume</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Skills System</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Multi-Provider</td><td>❌</td><td>✅</td><td>❌</td></tr><tr><td>Auto-Update</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Hooks System</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Runtime Model Switch</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>IDE Integration</td><td>❌</td><td>❌</td><td>✅</td></tr></tbody></table><hr><p><em>Last updated: April 2026</em></p>',29)])])}const m=e(r,[["render",n]]);export{u as __pageData,m as default};
